import json
from pathlib import Path
from typing import Any, Dict, Optional

import pokebase as pb

CACHE_DIR = Path("seed_cache")
POKEMON_CACHE = CACHE_DIR / "pokemon_loc"
POKEMON_CACHE.mkdir(parents=True, exist_ok=True)


def _to_jsonable(obj: Any) -> Any:
    """
    Convert Pokebase objects to plain JSONable primitives.
    We only keep the bits we need, so this is minimal.
    """
    if obj is None or isinstance(obj, (str, int, float, bool)):
        return obj
    if isinstance(obj, (list, tuple)):
        return [_to_jsonable(x) for x in obj]
    if isinstance(obj, dict):
        return {str(k): _to_jsonable(v) for k, v in obj.items()}

    # Pokebase resources have .name and .id_ often
    name = getattr(obj, "name", None)
    if name is not None:
        return str(name)
    id_ = getattr(obj, "id_", None)
    if id_ is not None:
        return int(id_)

    # Fallback: string representation (last resort)
    return str(obj)


def pokemon_get_loc(identifier: str | int, *, use_cache: bool = True) -> Dict[str, Any]:
    """
    Fast path for seeding your Species + Gen3 typing tables.
    Avoids expensive fields (like location encounters).
    """
    # normalize cache key
    key = str(identifier).lower()
    cache_path = POKEMON_CACHE / f"{key}.json"

    if use_cache and cache_path.exists():
        return json.loads(cache_path.read_text(encoding="utf-8"))

    print(f"fetching pokemon({identifier})")
    p = pb.pokemon(identifier)

    data = []
    for loc in p.location_area_encounters:
        version_details = []
        area_name = loc.location_area.name
        area_id = loc.location_area.id_
        for ver in loc.version_details:
            version_name = ver.version.name
            version_id = ver.version.id_
            version_details.append({
                'version_name': version_name.capitalize(),
                'version_id': version_id})
        data.append({
            'area_name': area_name,
            'area_id': area_id,
            'version_details': version_details,

        })

    cache_path.write_text(json.dumps(data, indent=2), encoding="utf-8")
    return data

